fun solve(s: String, k: Long): String {
    val result = mutableListOf<Char>()

    for (c in s) {
        when (c) {
            'a'..'z' -> result.add(c)
            '*' -> {
                if (result.isNotEmpty()) {
                    result.removeAt(result.size - 1)
                }
            }
            '#' -> {
                val size = result.size
                for (i in 0 until size) {
                    result.add(result[i])
                }
            }
            '%' -> {
                result.reverse()
            }
        }
    }

    return if (k < 0 || k >= result.size.toLong()) "." else result[k].toString()
}
